import { WorkflowRuntime } from 'mastra';
import { z } from 'zod';

const expectedSchema = z.object({
  intent: z.string(),
  entities: z.array(z.object({ type: z.string(), value: z.string() })),
});

function detectSchemaDrift(workflow: WorkflowRuntime) {
  workflow.on('node:output', (output, node) => {
    const validation = expectedSchema.safeParse(output);
    if (!validation.success) {
      console.error(`Schema drift in ${node.id}:`, validation.error);
      return { valid: false, errors: validation.error.issues };
    }
    return { valid: true };
  });
}

import { AgentRuntime } from 'mastra/agent';

function validateToolResponses(agent: AgentRuntime) {
  agent.onToolCall(async (toolCall, context) => {
    const result = await toolCall.execute();
    const toolSchema = toolCall.tool.schema;

    const isValid = toolSchema.safeParse(result);
    if (!isValid.success) {
      throw new Error(`Tool ${toolCall.tool.name} returned malformed data: ${JSON.stringify(isValid.error.issues)}`);
    }
    return result;
  });
}

import { KnowledgeRuntime } from 'mastra/knowledge';

function detectStaleContext(knowledge: KnowledgeRuntime) {
  knowledge.onRetrieve((docs, query) => {
    const now = Date.now();
    const staleDocs = docs.filter(doc => (now - doc.timestamp) > 24 * 60 * 60 * 1000);

    if (staleDocs.length > 0) {
      console.warn(`Retrieved ${staleDocs.length} stale docs for query: ${query}`);
      return { hasStale: true, count: staleDocs.length };
    }
    return { hasStale: false };
  });
}

