import { createMiddleware } from 'mastra/workflow';
import { z } from 'zod';

const validationMiddleware = createMiddleware({
  name: 'output-validator',
  async process(input, context) {
    const schema = context.node.schema;
    const validated = schema.safeParse(input);

    if (!validated.success) {
      throw new Error(`Validation failed: ${JSON.stringify(validated.error.issues)}`);
    }

    return validated.data;
  },
});

export default validationMiddleware;

import { AgentTool } from 'mastra/agent';

function createSafeTool(tool: AgentTool) {
  return {
    ...tool,
    async execute(input: any) {
      let result = await tool.execute(input);

      // Normalize common malformations
      if (typeof result === 'string') {
        try {
          result = JSON.parse(result);
        } catch {
          result = { error: 'Parse failed', raw: result };
        }
      }

      return tool.schema.parse(result);
    },
  };
}

