import { Vex } from '@vex_dev/sdk';
import { AgentRuntime, WorkflowRuntime } from 'mastra';

const vex = new Vex({
  projectId: 'your-project-id',
  agentFramework: 'mastra',
});

export async function createInstrumentedAgent() {
  const agent = new AgentRuntime({ /* config */ });
  const workflow = new WorkflowRuntime({ /* config */ });

  // Add Vex as first middleware
  agent.use(vex.middleware({
    assertions: {
      'workflow-validation': 'step outputs match schema',
      'tool-responses': 'tools return valid JSON',
      'memory-freshness': 'context < 24h old',
      'sync-consistency': 'external data matches expected shape',
    },
  }));

  workflow.use(vex.middleware());

  return { agent, workflow };
}
